exercises.solution_code:
#include <cassert>
#include <expected>
#include <iostream>
#include <string>

std::expected<std::string, std::string> validate_password(std::string password)
{
    if (password.empty())
        return std::unexpected(std::string{"password is empty"});
    if (password.length() < 4)
        return std::unexpected(std::string{"password too short"});
    if (password.length() < 8)
        return std::string{"weak"};
    if (password.length() < 12)
        return std::string{"moderate"};
    return std::string{"strong"};
}

int main()
{
    std::string password;
    std::cin >> password;

    std::expected<std::string, std::string> result = validate_password(password);
    if (result)
        std::cout << "Strength: " << *result << '\n';
    else
        std::cout << "Error: " << result.error() << '\n';

    return 0;
}

