exercises.solution_code:
#include <cassert>
#include <climits>
#include <expected>
#include <iostream>
#include <stdexcept>
#include <string>

std::expected<int, std::string> safe_divide(int dividend, int divisor)
{
    if (divisor == 0)
        return std::unexpected(std::string{"division by zero"});
    if (dividend == INT_MIN && divisor == -1)
        throw std::overflow_error("overflow");
    return dividend / divisor;
}

void process_divisions(int dividend, int divisor)
{
    try
    {
        std::expected<int, std::string> result = safe_divide(dividend, divisor);
        if (result)
            std::cout << "Result: " << *result << '\n';
        else
            std::cout << "Error: " << result.error() << '\n';
    }
    catch (const std::overflow_error& e)
    {
        std::cout << "Exception: " << e.what() << '\n';
    }
}

int main()
{
    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i)
    {
        int a{}, b{};
        std::cin >> a >> b;
        process_divisions(a, b);
    }
    return 0;
}
